1	const PROCESSING_FEE = 5;
2	const COMPONENT_BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_TYPES = ["rune", "moonstone"];
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	type Item = { type: string; cursed?: boolean; enchantment?: number };
20	
21	const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
22	
23	const isHighlyEnchanted = (item: Item): boolean =>
24	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
25	
26	const surchargeRate = (item: Item): number =>
27	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
28	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
29	
30	const mainItemPremium = (item: Item): number => {
31	  const base = basePremiumFor(item);
32	  return base + base * surchargeRate(item);
33	};
34	
35	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
36	
37	const componentGroupPremium = (group: Item[]): number =>
38	  group.length === COMPONENT_BLOCK_SIZE
39	    ? COMPONENT_BLOCK_PREMIUM
40	    : group.reduce((sum, item) => sum + basePremiumFor(item), 0);
41	
42	const groupComponentsByType = (items: Item[]): Item[][] => {
43	  const groups: Record<string, Item[]> = {};
44	  for (const item of items) {
45	    (groups[item.type] ||= []).push(item);
46	  }
47	  return Object.values(groups);
48	};
49	
50	export function quote(customer: { yearsWithMHPCO: number }, items: Item[]): number {
51	  const components = items.filter(isComponent);
52	  const mainItems = items.filter((item) => !isComponent(item));
53	  const mainTotal = mainItems.reduce((sum, item) => sum + mainItemPremium(item), 0);
54	  const componentTotal = groupComponentsByType(components).reduce(
55	    (sum, group) => sum + componentGroupPremium(group),
56	    0,
57	  );
58	  const basePremium = mainTotal + componentTotal;
59	  const loyaltyDiscount =
60	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
61	  return basePremium - loyaltyDiscount + PROCESSING_FEE;
62	}
